import { jsPDF } from 'jspdf';

/**
 * Noto Sans SC 子集字体（~143 个中文字符，39KB）
 * 用于 jsPDF 中文输出，嵌入为 base64
 * 使用前需调用 registerChineseFont(doc)，然后 doc.setFont('NotoSansSC')
 */

// 子集字体 base64 数据由构建脚本注入
const FONT_DATA: string = '';

export function registerChineseFont(doc: jsPDF): void {
  const fonts = doc.getFontList();
  if (fonts && fonts['NotoSansSC']) return;
  try {
    doc.addFileToVFS('NotoSansSC-Regular.ttf', FONT_DATA);
    doc.addFont('NotoSansSC-Regular.ttf', 'NotoSansSC', 'normal');
  } catch {
    // 忽略重复注册
  }
}
